import { useState, useRef, useEffect } from "react";
import { useNavigate, Link } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import "../App.css";

const LoginPage = () => {
  const [identifier, setIdentifier] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");

  const [identifierFocus, setIdentifierFocus] = useState(false);
  const [passwordFocus, setPasswordFocus] = useState(false);
  const [buttonHover, setButtonHover] = useState(false);
  const [buttonActive, setButtonActive] = useState(false);

  const navigate = useNavigate();
  const identifierRef = useRef(null);

  const { login } = useAuth();

  useEffect(() => {
    identifierRef.current?.focus();
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");

    try {
      const user = await login(identifier, password);

      // ✅ SAFE ROLE HANDLING (prevents undefined crash)
      const role = (user?.role || "user").toLowerCase();

      navigate(role === "admin" ? "/admin" : "/profile");

    } catch (err) {
      setError(
        err.response?.data?.message ||
        err.message ||
        "Login failed. Please check your credentials."
      );
    }
  };

  const styles = {
    page: {
      backgroundColor: "#FAE8ED",
      minHeight: "100vh",
      display: "flex",
      justifyContent: "center",
      alignItems: "center",
      fontFamily: "Georgia, serif",
      padding: "20px",
      color: "rgb(12, 75, 52)",
    },
    container: {
      backgroundColor: "#f7c6d9",
      padding: "40px",
      borderRadius: "20px",
      boxShadow: "0 10px 30px rgba(0,0,0,0.1)",
      maxWidth: "400px",
      width: "100%",
      textAlign: "center",
    },
    heading: {
      fontSize: "36px",
      marginBottom: "20px",
      fontWeight: "bold",
    },
    form: {
      display: "flex",
      flexDirection: "column",
      gap: "18px",
    },
    input: {
      padding: "15px 20px",
      borderRadius: "50px",
      border: "2px solid transparent",
      fontSize: "16px",
      outline: "none",
      backgroundColor: "#f7c6d9",
      color: "rgb(12, 75, 52)",
    },
    inputFocus: {
      backgroundColor: "#ffffff",
      borderColor: "rgb(12, 75, 52)",
    },
    button: {
      padding: "16px 40px",
      borderRadius: "50px",
      border: "none",
      fontWeight: "bold",
      fontSize: "16px",
      cursor: "pointer",
      backgroundColor: "rgb(12, 75, 52)",
      color: "#f7c6d9",
      transition: "0.3s",
    },
    buttonHover: {
      backgroundColor: "rgb(241, 125, 194)",
      color: "#fff",
      transform: "scale(1.05)",
    },
    buttonActive: {
      transform: "scale(0.98)",
    },
    error: {
      color: "#ff4d4d",
      marginBottom: "10px",
    },
    link: {
      color: "rgb(12, 75, 52)",
      fontWeight: "bold",
      textDecoration: "none",
    },
  };

  const getButtonStyle = () => {
    if (buttonActive) return { ...styles.button, ...styles.buttonActive };
    if (buttonHover) return { ...styles.button, ...styles.buttonHover };
    return styles.button;
  };

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <h2 style={styles.heading}>Login</h2>

        {error && <p style={styles.error}>{error}</p>}

        <form style={styles.form} onSubmit={handleSubmit}>
          <input
            type="text"
            placeholder="Email or Username"
            value={identifier}
            onChange={(e) => setIdentifier(e.target.value)}
            ref={identifierRef}
            required
            style={
              identifierFocus
                ? { ...styles.input, ...styles.inputFocus }
                : styles.input
            }
            onFocus={() => setIdentifierFocus(true)}
            onBlur={() => setIdentifierFocus(false)}
          />

          <input
            type="password"
            placeholder="Password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            required
            style={
              passwordFocus
                ? { ...styles.input, ...styles.inputFocus }
                : styles.input
            }
            onFocus={() => setPasswordFocus(true)}
            onBlur={() => setPasswordFocus(false)}
          />

          <button
            type="submit"
            style={getButtonStyle()}
            onMouseEnter={() => setButtonHover(true)}
            onMouseLeave={() => setButtonHover(false)}
            onMouseDown={() => setButtonActive(true)}
            onMouseUp={() => setButtonActive(false)}
          >
            Login
          </button>
        </form>

        <p style={{ marginTop: "20px" }}>
          Don't have an account?{" "}
          <Link to="/register" style={styles.link}>
            Register here
          </Link>
        </p>
      </div>
    </div>
  );
};

export default LoginPage;
